/**
 * PDF Font Embedding — Termina + Aeonik Pro for jsPDF
 * Auto-generated base64 from public/fonts/*.otf
 * Only loaded when user downloads a PDF (lazy import).
 */

import type jsPDF from 'jspdf';

const TERMINA_MEDIUM_B64 = '';

const AEONIK_REGULAR_B64 = '';

const AEONIK_MEDIUM_B64 = '';

/**
 * Register Termina and Aeonik Pro with a jsPDF instance.
 * Call once before drawing text. Falls back silently on error.
 *
 * After registration:
 *   doc.setFont('Termina', 'normal')   → Termina Medium (weight 500)
 *   doc.setFont('AeonikPro', 'normal') → Aeonik Pro Regular (weight 400)
 *   doc.setFont('AeonikPro', 'medium') → Aeonik Pro Medium (weight 500)
 */
export function registerPdfFonts(doc: jsPDF): boolean {
  try {
    doc.addFileToVFS('Termina-Medium.otf', TERMINA_MEDIUM_B64);
    doc.addFont('Termina-Medium.otf', 'Termina', 'normal');

    doc.addFileToVFS('AeonikPro-Regular.otf', AEONIK_REGULAR_B64);
    doc.addFont('AeonikPro-Regular.otf', 'AeonikPro', 'normal');

    doc.addFileToVFS('AeonikPro-Medium.otf', AEONIK_MEDIUM_B64);
    doc.addFont('AeonikPro-Medium.otf', 'AeonikPro', 'medium');

    return true;
  } catch (err) {
    console.warn('[pdf-fonts] Font registration failed, falling back to Helvetica:', err);
    return false;
  }
}

/** Convenience: set Termina with tracking (charSpace approximating 0.08em at given fontSize) */
export function setTermina(doc: jsPDF, fontSize: number): void {
  doc.setFont('Termina', 'normal');
  doc.setFontSize(fontSize);
}

/** Convenience: set Aeonik Pro regular */
export function setAeonik(doc: jsPDF, fontSize: number, style: 'normal' | 'medium' = 'normal'): void {
  doc.setFont('AeonikPro', style);
  doc.setFontSize(fontSize);
}
